@Service
class AuthorizationCodeStore {

    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();

    public void store(String code, AuthorizationCode authorizationCode) {
        cleanupExpired();
        codes.put(code, authorizationCode);
    }

    public Optional<AuthorizationCode> consume(String code) {
        cleanupExpired();
        AuthorizationCode stored = codes.remove(code);
        if (stored == null || stored.getExpiresAt().isBefore(Instant.now())) {
            return Optional.empty();
        }
        return Optional.of(stored);
    }

    public Optional<AuthorizationCode> find(String code) {
        cleanupExpired();
        AuthorizationCode stored = codes.get(code);
        if (stored == null || stored.getExpiresAt().isBefore(Instant.now())) {
            codes.remove(code);
            return Optional.empty();
        }
        return Optional.of(stored);
    }

    private void cleanupExpired() {
        Instant now = Instant.now();
        codes.entrySet().removeIf(entry -> entry.getValue().getExpiresAt().isBefore(now));
    }
}

